import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import API from '../api/axios';

const ProfilePage = () => {
  const { user, setUser } = useAuth();

  const [name, setName] = useState(user?.name || '');
  const [username, setUsername] = useState(user?.username || '');
  const [bio, setBio] = useState(user?.bio || '');
  const [pic, setPic] = useState(null);
  const [preview, setPreview] = useState(null);
  const [curPw, setCurPw] = useState('');
  const [newPw, setNewPw] = useState('');
  const [showPw, setShowPw] = useState(false);
  const [toast, setToast] = useState({ msg: '', type: '' });
  const [darkMode, setDarkMode] = useState(false);

  /* ================= THEME LOGIC ================= */
  useEffect(() => {
    const saved = localStorage.getItem("user-theme");
    setDarkMode(saved === "dark");
  }, []);

  // NEW: Function to actually switch the mode
  const toggleTheme = () => {
    const newMode = !darkMode;
    setDarkMode(newMode);
    localStorage.setItem("user-theme", newMode ? "dark" : "light");
  };

  /* ================= TOAST AUTO HIDE ================= */
  useEffect(() => {
    if (!toast.msg) return;
    const timer = setTimeout(() => setToast({ msg: '', type: '' }), 3000);
    return () => clearTimeout(timer);
  }, [toast]);

  /* ================= PROFILE UPDATE ================= */
  const handleProfile = async (e) => {
    e.preventDefault();
    const fd = new FormData();
    fd.append('name', name);
    fd.append('bio', bio);
    fd.append('username', username);
    if (pic) fd.append('profilePic', pic);

    try {
      const { data } = await API.put('/auth/profile', fd);
      setUser(data);
      setToast({ msg: 'Profile updated successfully!', type: 'success' });
    } catch (err) {
      setToast({ msg: err.response?.data?.message || 'Error updating profile', type: 'error' });
    }
  };

  /* ================= PASSWORD UPDATE ================= */
  const handlePassword = async (e) => {
    e.preventDefault();
    try {
      await API.put('/auth/change-password', {
        currentPassword: curPw,
        newPassword: newPw,
      });
      setToast({ msg: 'Password changed successfully!', type: 'success' });
      setCurPw('');
      setNewPw('');
    } catch (err) {
      setToast({ msg: err.response?.data?.message || 'Error changing password', type: 'error' });
    }
  };

  /* ================= IMAGE PREVIEW ================= */
  const handleFileChange = (file) => {
    setPic(file);
    if (file) {
      setPreview(URL.createObjectURL(file));
    }
  };

  const picSrc = preview
    ? preview
    : user?.profilePic
    ? `http://localhost:5000/uploads/${user.profilePic}`
    : '/default-avatar.png';

  /* ================= STYLES ================= */
  const styles = {
    page: {
      background: darkMode ? "#1a000e" : "#fdf2f5",
      minHeight: '100vh',
      padding: '60px 20px',
      display: 'flex',
      justifyContent: 'center',
      transition: 'all 0.3s ease',
      fontFamily: 'system-ui, sans-serif'
    },
    container: {
      width: '100%',
      maxWidth: '600px',
      display: 'flex',
      flexDirection: 'column',
      gap: '24px',
    },
    card: {
      background: darkMode ? "#2e091e" : "#ffffff",
      borderRadius: '24px',
      padding: '32px',
      boxShadow: darkMode ? "0 10px 30px rgba(0,0,0,0.5)" : "0 10px 25px rgba(220,180,190,0.3)",
      color: darkMode ? "#eee" : "#333",
      border: darkMode ? "1px solid #4a1030" : "1px solid #eee",
    },
    header: { textAlign: "center", display: "flex", flexDirection: "column", alignItems: "center" },
    profilePic: {
      width: '130px',
      height: '130px',
      borderRadius: '50%',
      objectFit: 'cover',
      marginBottom: "16px",
      border: `4px solid ${darkMode ? "#c46392" : "#fff"}`,
    },
    username: { fontWeight: "800", fontSize: "22px", color: darkMode ? "#ff9dc8" : "#560032" },
    bio: { fontSize: "15px", marginTop: "8px", opacity: 0.8 },
    title: {
      fontWeight: "bold",
      marginBottom: "20px",
      fontSize: "18px",
      color: darkMode ? "#ff9dc8" : "#560032",
      borderBottom: `1px solid ${darkMode ? "#4a1030" : "#f0f0f0"}`,
      paddingBottom: "10px"
    },
    input: {
      width: "100%",
      padding: "14px",
      borderRadius: "12px",
      border: darkMode ? "1px solid #4a1030" : "1px solid #ddd",
      marginBottom: "16px",
      backgroundColor: darkMode ? "#1a000e" : "#fafafa",
      color: darkMode ? "#fff" : "#000",
      boxSizing: "border-box",
    },
    textarea: {
      width: "100%",
      padding: "14px",
      borderRadius: "12px",
      border: darkMode ? "1px solid #4a1030" : "1px solid #ddd",
      marginBottom: "16px",
      backgroundColor: darkMode ? "#1a000e" : "#fafafa",
      color: darkMode ? "#fff" : "#000",
      boxSizing: "border-box",
      resize: "none",
    },
    button: {
      width: "100%",
      padding: "14px",
      borderRadius: "12px",
      border: "none",
      cursor: "pointer",
      fontWeight: "bold",
      backgroundColor: darkMode ? "#c46392" : "#0c4b34",
      color: "#fff",
    },
    themeToggle: {
      alignSelf: "flex-end",
      padding: "8px 16px",
      borderRadius: "20px",
      border: "none",
      cursor: "pointer",
      backgroundColor: darkMode ? "#ff9dc8" : "#560032",
      color: darkMode ? "#560032" : "#fff",
      fontWeight: "bold",
      fontSize: "12px"
    },
    toast: {
      position: "fixed",
      top: "30px",
      right: "30px",
      padding: "16px 24px",
      borderRadius: "12px",
      color: "#fff",
      backgroundColor: toast.type === "success" ? "#10b981" : "#ef4444",
      zIndex: 1000,
    },
  };

  return (
    <div style={styles.page}>
      {toast.msg && <div style={styles.toast}>{toast.msg}</div>}

      <div style={styles.container}>
        
        {/* NEW THEME TOGGLE BUTTON */}
        <button onClick={toggleTheme} style={styles.themeToggle}>
          {darkMode ? "☀️ LIGHT MODE" : "🌙 DARK MODE"}
        </button>

        <div style={styles.card}>
          <div style={styles.header}>
            <img src={picSrc} alt="Profile" style={styles.profilePic} />
            <div style={styles.username}>@{user?.username}</div>
            <div style={styles.bio}>{user?.bio || "No bio yet."}</div>
          </div>
        </div>

        <form style={styles.card} onSubmit={handleProfile}>
          <div style={styles.title}>Edit Profile</div>
          <input value={name} onChange={(e) => setName(e.target.value)} placeholder="Name" style={styles.input} />
          <input value={user?.email || ""} disabled style={{...styles.input, opacity: 0.5}} />
          <input value={username} onChange={(e) => setUsername(e.target.value)} placeholder="Username" style={styles.input} />
          <textarea value={bio} onChange={(e) => setBio(e.target.value)} rows={3} style={styles.textarea} />
          <input type="file" onChange={(e) => handleFileChange(e.target.files[0])} style={{marginBottom: '15px'}} />
          <button type="submit" style={styles.button}>Save Changes</button>
        </form>

        <form style={styles.card} onSubmit={handlePassword}>
          <div style={styles.title}>Security</div>
          <div style={{position: 'relative'}}>
            <input type={showPw ? "text" : "password"} placeholder="Current password" value={curPw} onChange={(e) => setCurPw(e.target.value)} style={styles.input} />
            <span onClick={() => setShowPw(!showPw)} style={{position:'absolute', right:'15px', top:'15px', cursor:'pointer', fontSize:'12px', color: darkMode ? '#ff9dc8' : '#0c4b34'}}>{showPw ? "HIDE" : "SHOW"}</span>
          </div>
          <input type={showPw ? "text" : "password"} placeholder="New password" value={newPw} onChange={(e) => setNewPw(e.target.value)} style={styles.input} />
          <button type="submit" style={styles.button}>Update Password</button>
        </form>
      </div>
    </div>
  );
};

export default ProfilePage;
